async function testServeApp() {
  const BASE = 'http://localhost:3001';
  const res = await fetch(BASE + '/');
  assertEquals(res.status, 200, 'Should return 200');

  const html = await res.text();

  // Check for required structural elements
  assert(html.includes('id="map"'), 'Should contain map div');
  assert(html.includes('id="weather-canvas"'), 'Should contain weather canvas');
  assert(html.includes('id="conditions-panel"'), 'Should contain conditions panel');
  assert(html.includes('id="compass-panel"'), 'Should contain compass panel');
  assert(html.includes('id="timeline-panel"'), 'Should contain timeline panel');
  assert(html.includes('id="info-bar"'), 'Should contain info bar');
  assert(html.includes('id="layer-panel"'), 'Should contain layer panel');
  assert(html.includes('id="action-buttons"'), 'Should contain action buttons');

  // Route planner panel + its body container
  assert(html.includes('id="route-panel"'), 'Should contain route planner panel');
  assert(html.includes('id="route-panel-body"'), 'Should contain route panel body');
  assert(html.includes('route-panel-title'), 'Should contain route panel title');

  // Check for asset references
  assert(html.includes('sailing-weather.css'), 'Should reference app CSS');
  assert(html.includes('/api/sailing-js'), 'Should reference app JS via handler');
  assert(html.includes('sailing-water-detect.css'), 'Should reference water detection CSS');
  assert(html.includes('sailing-overlays.css'), 'Should reference overlays CSS');
  assert(html.includes('sailing-drag.css'), 'Should reference draggable handle CSS');
  assert(html.includes('sailing-route.css'), 'Should reference route planner CSS');

  // Check for Leaflet references
  assert(html.includes('leaflet'), 'Should reference Leaflet');

  // Check meta tags
  assert(html.includes('<!DOCTYPE html>'), 'Should have doctype');
  assert(html.includes('viewport'), 'Should have viewport meta');

  // Check play button is present with correct attributes
  assert(html.includes('id="timeline-play-btn"'), 'Should contain play button');
  assert(html.includes('aria-label="Play forecast animation"'), 'Play button should have aria-label');
  assert(html.includes('data-play-interval="1500"'), 'Play button should have injected config interval');

  // The route panel should have its config-injected default speed (placeholder resolved)
  assert(html.includes('data-default-speed="5"'), 'Route panel should have injected default speed');

  // Verify no unresolved template placeholders
  assert(!html.includes('{{PLAY_INTERVAL_MS}}'), 'Should not contain unresolved play interval placeholder');
  assert(!html.includes('{{ROUTE_DEFAULT_SPEED}}'), 'Should not contain unresolved route speed placeholder');

  // Check overlay layer toggles are present
  assert(html.includes('data-layer="radar"'), 'Should have radar layer toggle');
  assert(html.includes('data-layer="cloudMap"'), 'Should have cloud map layer toggle');
  assert(html.includes('data-layer="pressureMap"'), 'Should have pressure map layer toggle');
  assert(html.includes('layer-separator'), 'Should have layer separator');
  assert(html.includes('layer-panel-subtitle'), 'Should have overlay subtitle');

  // Check draggable grip handles — one per floating control (7 total now)
  assert(html.includes('class="drag-handle"'), 'Should contain drag handles');
  assert(html.includes('class="grip-dots"'), 'Should contain grip dots');
  const handleCount = html.split('class="drag-handle"').length - 1;
  assertEquals(handleCount, 7, 'Should render a drag handle for all seven floating controls');
}
